#include<cstdio>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline int Get(){char ch;do ch=getchar();while((ch<'a'||ch>'z')&&ch!='?');return ch=='?'?-1:ch-'a';}
const int N=1010,Mod=998244353,M=2e5+10;int df[N][N],np[N][N],n,a[N],nm,qS[M],ans[1<<17],s[1<<17],pw[18][N];std::vector<int> PP[18];
inline int qpow(int a,int b){int r(1);while(b)b&1?r=1ll*a*r%Mod:0,a=1ll*a*a%Mod,b=b>>1;return r;}
inline void DN(int &x){x>=Mod?x-=Mod:0;}
int main()
{
//	FIN("data.in");FOUT("qwq.out");
	n=read();rep(1,n,i)nm+=(a[i]=Get())==-1;
	rep(0,nm,i)pw[0][i]=0,pw[1][i]=1;rep(2,17,i){pw[i][0]=1;rep(1,nm,j)pw[i][j]=1ll*pw[i][j-1]*i%Mod;}
	rep(1,n,i)df[i][i-1]=df[i][i]=nm;
	for(int T=2;T<=n;++T)for(int l=1,r=T;r<=n;++l,++r)
	{
		if(df[l+1][r-1]==-1||(a[l]!=a[r]&&a[l]!=-1&&a[r]!=-1)){df[l][r]=-1;continue;}
		df[l][r]=df[l+1][r-1]+(a[l]==a[r]&&a[l]==-1)-(a[l]==-1)-(a[r]==-1);
		np[l][r]=np[l+1][r-1];if((a[l]==-1)^(a[r]==-1))np[l][r]|=(1<<(a[l]==-1?a[r]:a[l]));
	}
	for(int S=0;S<(1<<17);++S)PP[__builtin_popcount(S)].push_back(S);
	rep(0,17,i)
	{
		memset(s,0,sizeof(s)); rep(1,n,l)rep(l,n,r)DN(s[np[l][r]]+=pw[i][df[l][r]]);
		for(int i=0;i<17;++i)for(int S=1;S<(1<<17);++S)if((S>>i)&1)DN(s[S]+=s[S^(1<<i)]);
		for(int S:PP[i])ans[S]=s[S];
	}
	int Q=read();rep(1,Q,i)
	{
		char ch[20];scanf("%s",ch);int len=strlen(ch),SS=0;
		for(int j=0;j<len;++j)SS|=(1<<(ch[j]-'a'));print(ans[SS]);putchar('\n');
	}
}
